text:
Our dataset
I work in healthcare, so I’m going to make up a healthcare-esque dataset. We’ll be dealing with billing data for providers at a medical facility.

library(S7)
library(fabricatr)
library(tidyverse)

billing_data &lt;- fabricate(
  facility_id = add_level(N = 3, n_patients = sample(1:3, size = 1)),
  patient_id = add_level(
    n_patients,
    patient = randomNames::randomNames(n = N),
    n_dates = sample(1:3, size = N, replace = TRUE),
    n_billing_codes = sample(1:3, size = N, replace = TRUE),
    billing_codes = map_chr(
      n_billing_codes,
      ~ {
        sample(c("ABC123", "DEF456", "GHI789"), size = .x, replace = FALSE) |&gt;
          str_flatten_comma()
      }
    )
  ),
  date_of_service_id = add_level(
    N = n_dates,
    date_of_service = sample(
      seq_len(days_in_month(today())),
      size = N,
      replace = TRUE
    ) |&gt;
      make_date(year = 2026, month = month(today()), day = _)
  )
) |&gt;
  separate_longer_delim(
    billing_codes,
    delim = ", "
  ) |&gt;
  mutate(
    facility = paste0("FAC-", facility_id),
    minutes = sample(c(8, 10, 15, 30, 45, 60), size = n(), replace = TRUE)
  ) |&gt;
  rename(
    billing_code = billing_codes
  ) |&gt;
  transmute(
    facility,
    patient,
    date_of_service,
    billing_code,
    medical_code = "abc987",
    treatment_code = "def123",
    minutes
  ) |&gt;
  arrange(
    facility,
    patient,
    date_of_service,
    billing_code
  )

Each row in this dataset represents billable minutes for a medical service.

The generate_billing_export generic
Like S3 and S4, S7 uses function generics to operate on objects. We’re going to create a generic called generate_billing_export that will behave differently depending on the kind of billing export object we pass to it. We’ll present the code for creating the generic and the method implementation for PopularVendorBillingExport. I omit the rest for brevity.

generate_billing_export &lt;- new_generic(
  name = "generate_billing_export",
  dispatch_args = "x"
)

method(generate_billing_export, PopularVendorBillingExport) &lt;- function(
  x
) {
  d &lt;- x@data
  if (x@config$exclude_medical_code_field) {
    d &lt;- d |&gt;
      mutate(
        medical_code_field = ""
      )
  }
  if (x@config$exclude_treatment_code_field) {
    d &lt;- d |&gt;
      mutate(
        treatment_code_field = ""
      )
  }
  facility &lt;- d |&gt; pluck("facility", 1)
  d |&gt;
    readr::write_tsv(
      file = here::here(
        "data",
        glue::glue("popular-vendor-export_{facility}.tsv")
      ),
      na = ""
    )
  invisible(x)
}

It’s inside these method definitions that the bulk of our original R scripts will go. All of the logic for formatting fields, omitting fields, and so on, all gets included here. By passing the PopularVendorBillingExport object as an argument, we save ourselves having to pass a bunch of other arguments to the function. Everything the function needs is contained in the properties of the billing export object.

The new workflow
When we implement our S7 classes well, our program becomes more elegant and easier to reason about. Consider the code below.

generate_billing_export_safely &lt;- purrr::safely(
  generate_billing_export,
  otherwise = NULL
)

billing_exports &lt;- billing_data |&gt;
  nest(
    data = everything(),
    .by = c(facility, billing_export_type)
  ) |&gt;
  transmute(
    facility,
    billing_export_type,
    billing_export = map2(
      .x = billing_export_type,
      .y = data,
      .f = \(x, y) {
        be &lt;- billing_export(type = x, data = y)
        generate_billing_export_safely(be)
      }
    )
  )

Sometimes an error will occur generating an export for one facility and not the others. We don’t want one facility holding up the others, so we create a simple “safe” version of generate_billing_export called generate_billing_export_safely that returns NULL if we encounter an error. From there, generating billing exports for each facility reduces to another split-apply-combine workflow that we’re used to seeing in {dplyr} workflows. Regardless of how many new vendors we add, this code will still work the same way. Good design is powerful. There’s plenty of ways we can improve upon this script further.

The Typst template
The file sales-report-template.typ contains three custom functions that are worth explaining. Some details are omitted for brevity, but again, you can find the full source code in the repo.
The sales-report function

#let sales-report(
  title: "Monthly Sales Report",
  store-name: "Store Name",
  store-id: "000",
  report-period: "Month YYYY",
  report-date: datetime.today().display(),
  country: "",
  state: "",
  body
) = {
  // Color palette as variables for consistency
  let primary-color = rgb("#1e3a8a")
  let secondary-color = rgb("#3b82f6")
  // ... additional colors ...

  set page(
    paper: "us-letter",
    margin: (top: 2.5cm, bottom: 2.5cm, left: 2cm, right: 2cm),
    header: context {
      // First page gets branded header; subsequent pages get minimal header
      if counter(page).get().first() == 1 {
        // ... logo, company name, date ...
      } else {
        // ... store name, period, page number ...
      }
    }
  )

  // Heading styles using show rules
  show heading.where(level: 1): it =&gt; block(
    width: 100%,
    above: 24pt,
    below: 16pt,
    {
      text(size: 20pt, weight: "bold", fill: primary-color, it.body)
      v(6pt)
      line(length: 100%, stroke: 1.5pt + secondary-color)
    }
  )

  body
}

This function is responsible for top-level styling details for the entire document. We’re defining details like font, font color, appearance of headings, and so on. One thing worth noting is that Typst has a keyword context. This keyword allows us to manipulate content based on its position within a document. One of the things I wanted the sales report to have is a special header on the first page, but a minimal header on subsequent pages. The context keyword in Typst lets us express these kinds of things easily. Another thing to note is that we don’t fill in much content here. This is because the main body content is going to come from Quarto.
The info-box and kpi-box functions
These two functions create custom elements I wanted the sales report to have. The info-box function creates a dedicated container where I can call out important info about each store (trend info, top-performing categories, etc.). The kpi-box function gives me another special container where I can display information about store KPIs (see below).

#let kpi-box(title, value, change: none, color: rgb("#3b82f6")) = {
  box(
    width: 100%,
    fill: rgb("#f9fafb"),
    inset: 12pt,
    radius: 4pt,
    stroke: 1pt + rgb("#e5e7eb"),
    {
      text(size: 9pt, weight: "semibold", fill: rgb("#6b7280"), upper(title))
      v(4pt)
      text(size: 18pt, weight: "bold", fill: color, value)
      if change != none {
        v(2pt)
        text(
          size: 8pt,
          fill: if change &gt; 0 { rgb("#059669") } else { rgb("#dc2626") },
          weight: "medium",
          if change &gt; 0 { [↑ +#change%] } else { [↓ #change%] }
        )
      }
    }
  )
}

Notice how, instead of just providing the current value of the metric, the KPI box also shows things like the percent change since the last reporting period, and colors it differently based on whether the change is positive or negative. Writing functions like these really sold me on the power of Typst for crafting PDFs. I’ve loathed working with PDFs in the past, but Typst actually made the experience enjoyable.

The R script
We need a program that does the following. First, it takes the sales dataset and produces a data.frame containing all unique combinations of store_key, year, and month. Then, it iterates row-wise over this data.frame, calling a custom function generate_report that takes the values of the row as arguments and forwards them as parameters to the Quarto CLI to render the monthly sales report. In code, it’d look something like this.

library(contoso)
library(tibble)
library(dplyr)

# ... Other preamble code ...

results &lt;- store_months |&gt;
  group_by(
    store_key,
    year,
    month
  ) |&gt;
  group_map(
    \(x, y) {
      generate_report(
        store_key = y$store_key,
        year = y$year,
        month = y$month
      )
    }
  )

If you’re wondering what the second argument y is in the anonymous function, it’s a tibble containing one row and one column for each column passed to the group_by function. For more details on this, see the documentation for group_map. Anyway, at this level, the mechanics are pretty clear. Once I got this working, I noticed it was kind of slow. If I consider months for which a store had a minimum of 10 sales, I get 34 store-month combinations, and the app took ~1.8 minutes to produce all of them (~3.2 seconds per report). Not ideal. Fortunately, I was able to find a way to speed things up, and we’ll cover that in the next section.

What is modify_tree?
Here’s what the help page has to say.

modify_tree() allows you to recursively modify a list, supplying functions that either modify each leaf or each node (or both).

Like many other {purrr} functions, it’s a function for processing lists. But unlike functions like map and friends that move through lists iteratively, modify_tree traverses its input recursively. That is, it calls itself on successive child nodes until it reaches what are called leaf nodes, elements satisfying some base case. Leaf nodes are determined by a predicate function passed to the is_node argument of the function, which defaults to simple lists. So by default, any node that isn’t a simple list is considered a leaf node. As it moves through its input, modify_tree does what it says on the tin: it modifies nodes. Let’s look at a basic example.

library(purrr)

some_list &lt;- list(
    a = 1,
    b = list(
        c = 2,
        d = list(
            e = 3
        )
    ),
)

modify_tree(
    some_list,
    leaf = \(x){
        x + 1
    }
)

# Result:
# &lt;list&gt;
# ├─a: 2
# └─b: &lt;list&gt;
#   ├─c: 3
#   └─d: &lt;list&gt;
#     └─e: 4

We take the list some_list, and we add 1 to its leaf nodes. The transformation applied to the leaf nodes is passed to the leaf argument of modify_tree. For those that have done recursive stuff in R before, this might sound a lot like how base::rapply works, and you’d be right. In this case, modify_tree is equivalent to rapply. So why not just use rapply? The main reason is that modify_tree can modify all the nodes in its input, whereas rapply only modifies the leaf nodes1. As we’ll see later, this is a really cool feature that makes modify_tree a powerful tool for crafting elegant solutions to complex problems.

Transforming non-leaf nodes with pre and post
There are two arguments in modify_tree that can modify non-leaf nodes called pre and post. Let’s look at what the help file has to say about them.

pre, post Functions applied to each node. pre is applied on the way “down”, i.e. before the leaves are transformed with leaf, while post is applied on the way “up”, i.e. after the leaves are transformed.

While this is helpful, I still found this definition a little unclear, so let’s look at the source code of modify_tree as well to get a more complete picture.

function (x, ..., leaf = identity, is_node = NULL, pre = identity, 
    post = identity) 
{
    check_dots_empty()
    leaf &lt;- rlang::as_function(leaf)
    is_node &lt;- as_is_node(is_node)
    post &lt;- rlang::as_function(post)
    pre &lt;- rlang::as_function(pre)
    worker &lt;- function(x) {
        if (is_node(x)) {
            out &lt;- pre(x)
            out &lt;- modify(out, worker)
            out &lt;- post(out)
        }
        else {
            out &lt;- leaf(x)
        }
        out
    }
    worker(x)
}

Let’s dwell on all of this for a bit. What we care about is inside of the worker function. When we say, “on the way down”, we mean that the transformation pre is applied to the current node before recursing into the next level. Then, we recurse until we hit the leaves. Only after the leaves are transformed do we then perform the transformation post on the nodes pre transformed. This is what’s meant when we say that post is applied “on the way up”. (I will say that typing this out made things a lot clearer than just re-reading the help file a bunch.)
Now that we have a better understanding of when pre and post get applied, let’s consider a different kind of when; that is, when these transformations can be useful.

Uses of pre
The pre transformation is useful for standardizing node structures and pruning unneeded nodes before recursing into deeper levels. We’ll look at an example of each, starting with standardizing node structures.
Standardizing node structure
Imagine you’re analyzing a bunch of JSON responses from a REST API. The data you get back looks like the following.
[
  {
    "first_name": "Jim",
    "middle_name": "Bo",
    "last_name": "James"
  },
  {
    "first_name": "John",
    "last_name": "Doe"
  }
]
Sometimes REST APIs will omit a field entirely when it’s missing instead of including the field and setting its value to null. If we want to convert this JSON into a flat table, this field omission can lead to issues. Fortunately, modify_tree makes standardizing the field names easy.

library(purrr)

json |&gt;
  modify_tree(
    pre = \(x) {
      expected_names &lt;- c("first_name", "middle_name", "last_name")
      if (!rlang::is_named(x)) {
        return(x)
      }
      if (all(expected_names %in% names(x))) {
        return(x)
      }
      missing_names &lt;- setdiff(expected_names, names(x))
      x[missing_names] &lt;- NA
      return(x)
    }
  )

In the code above, we start with an expected set of names. We then check each node that’s a named list, and whenever one of the expected names is missing, we replace it with NA. Simple, easy, and nice. You can imagine a similar problem where the field name isn’t missing, but it was simply called something else a long time ago (e.g. middle_initial). You’ll see this sort of thing if you ever analyze API responses saved over time. You could use modify_tree here as well (this is left as an exercise for the reader.)
Pruning nodes
Sometimes we don’t care about every detail inside of a list. Other times, we may have some expensive calculation that we need to run on the nodes of a list, and we want to avoid any wasted computation on nodes where we know the answer. The pre argument can help us in both these cases. Suppose we’re still analyzing those JSON responses from earlier, and we’re only concerned with the people with a “J” last name. The following code gives us the filtered subset we need.

library(purrr)

json |&gt;
  modify_tree(
    pre = \(x) {
      if (!rlang::is_named(x)) {
        return(x)
      }
      if (has_name(x, "last_name") && startsWith(x$last_name, "J")) {
        return(x)
      }
      NULL
    }
  )

# Result:
# &lt;list&gt;
# ├─&lt;list&gt;
# │ ├─first_name: "Jim"
# │ ├─middle_name: "Bo"
# │ └─last_name: "James"
# └─&lt;NULL&gt;

Here, the code only returns named list nodes if they have a last_name field value that starts with “J”. It’s not great that we end up with a list of the same length with NULLs replacing the people that were filtered out, but we’ll see that we can improve on that a little later using the post transformation. The fact that we can return NULL from pre instead of the node passed in is a subtle but powerful feature of modify_tree. Normally, modify_tree will recurse into its input until it reaches the leaves, applying computations as it goes. This pruning effect allows us to short-circuit modify_tree from making further recursive calls from that node, resulting in more efficient processing of larger, complex lists.


Using post
So what about post? I find post useful in at least two situations. One is when you want to further clean up nodes pruned by pre. Another is changing the structure of the output, like going from a nested list to a flat table. We’ll look at an example of both.
Pruning nodes (improved)
We can improve on the filtering we did in the previous example by combining it with post. Since post sees nodes after being processed by pre and leaf, we can perform transformations that are complementary to the ones before them (e.g. removing NULL entries from the list of people returned). The example below shows how we can do that.

library(purrr)

json |&gt;
  modify_tree(
    pre = \(x) {
      if (!rlang::is_named(x)) {
        return(x)
      }
      if (has_name(x, "last_name") && startsWith(x$last_name, "J")) {
        return(x)
      }
    },
    post = \(x) {
      compact(x)
    }
  )

# Result:
# &lt;list&gt;
# └─&lt;list&gt;
#   ├─first_name: "Jim"
#   ├─middle_name: "Bo"
#   └─last_name: "James"

While this is great, I think it’s more cool to look at how post can produce an output with a completely different structure than its input. We often get nested lists when the data we’re dealing with is API responses. Once we have these lists, we usually want to transform them into a flattened table so we can manipulate them further using tools like {dplyr}, {data.table}, and so on. Let’s look at an example of converting a deeply nested list into a table using modify_tree.
Rectangling nested lists
Suppose we have a JSON payload that lists the hierarchical details of a company down to its employees. An example is given below.
{
  "id": "6a995562-3cd1-443c-8d37-505978b97aed",
  "name": "Big Company",
  "regions": [
    {
      "id": "292beace-47e7-4cf4-bb92-07878795c337",
      "name": "Region A",
      "facilities": [
        {
          "id": "c9f10e7a-7826-4b24-9824-9e20c4308f8a",
          "name": "Facility Red",
          "employees": [
            {
              "id": "a766b675-f69d-4a0f-b361-855256a27821",
              "name": "Satrina"
            },
            {
              "id": "13d9754a-a2a6-4d15-99a0-dbe4fa3cb43f",
              "name": "Margeree"
            }
          ]
        },
        {
          "id": "3b0b6e34-e299-4cad-bd65-a201eb62ab62",
          "name": "Facility Blue",
          "employees": [
            {
              "id": "30923db3-e9df-46bc-aa8f-a21e539dcb38",
              "name": "Aariona"
            },
            {
              "id": "761c8c35-0ce2-4bb5-a3aa-75c381c4890a",
              "name": "Letrina"
            },
            {
              "id": "c10a15cf-df8f-40ac-b290-ffa7ff39b046",
              "name": "Ehron"
            }
          ]
        },
        {
          "id": "33e761a5-6f90-44dd-bbbb-77f7d5a508b6",
          "name": "Facility Green",
          "employees": [
            {
              "id": "352a605a-559a-436d-8ea9-63d1914ad158",
              "name": "Uyless"
            }
          ]
        }
      ]
    },
    {
      "id": "53a813cc-8e6a-4542-ab20-2af96bf3517e",
      "name": "Region B",
      "facilities": [
        {
          "id": "07d1053c-1590-42e9-a03f-21f2ae3e55c0",
          "name": "Facility Yellow",
          "employees": [
            {
              "id": "b1474078-da33-44a6-b6b8-e5a5f6b2320b",
              "name": "Uche"
            },
            {
              "id": "7a1bbb06-45f0-4c48-851c-4416b5ebb345",
              "name": "Lilliam"
            },
            {
              "id": "eee36fb8-8bde-4c06-a97f-27c8d35a9bbd",
              "name": "Vaidehi"
            },
            {
              "id": "fc6d2504-9702-4c69-84b5-bfd6d7a387ca",
              "name": "Shieka"
            }
          ]
        }
      ]
    }
  ]
} 
If you stare at this mess long enough, you’ll see there are four entities represented, the company, the regions of the company, the facilities in each region, and the employees that work in each facility. We want to take this nested JSON and turn it into a flat table. We can do this using modify_tree and post as follows.

library(purrr)
library(tibble)

company_df &lt;- modify_tree(
  company_json,
  post = \(x) {
    if (every(x, rlang::is_atomic)) {
      return(as_tibble(x))
    }
    if (none(x, rlang::is_atomic)) {
      return(list_rbind(x))
    }
    if (some(x, rlang::is_atomic)) {
      atomics &lt;- keep(x, rlang::is_atomic) |&gt; as_tibble()
      non_atomics &lt;- keep(x, negate(rlang::is_atomic)) |&gt; pluck(1)
      out &lt;- list_cbind(
        list(atomics, non_atomics)
      )
      return(out)
    }
  }
) |&gt;
  set_names(
    c(
      "company_id",
      "company",
      "region_id",
      "region",
      "facility_id",
      "facility",
      "employee_id",
      "employee"
    )
  )

#  Result (ID columns omitted for brevity):
#  A tibble: 10 × 4
#    company     region   facility        employee  
#    &lt;chr&gt;       &lt;chr&gt;    &lt;chr&gt;           &lt;chr&gt;
#  1 Big Company Region A Facility Red    Satrina   
#  2 Big Company Region A Facility Red    Margeree  
#  3 Big Company Region A Facility Blue   Aariona   
#  4 Big Company Region A Facility Blue   Letrina   
#  5 Big Company Region A Facility Blue   Ehron     
#  6 Big Company Region A Facility Green  Uyless    
#  7 Big Company Region B Facility Yellow Uche      
#  8 Big Company Region B Facility Yellow Lilliam   
#  9 Big Company Region B Facility Yellow Vaidehi   
# 10 Big Company Region B Facility Yellow Shieka      

Let’s unpack this. Since post occurs “on the way up”, we should start with the lowest level of the list, the level of the employee. Each employee list is basically a single row table, so we can convert it to a single row tibble via as_tibble. What’s the next level up? This would be the employees node. By the time we get here, the employees lists have been turned into tables, so we can stack them row-wise into a single table via list_rbind. What about after that? The next level is the facility node. At this point, we have a list containing the facility’s ID, name, and a table containing all its employees. We want to combine all of this information into a single table. To do this, we basically take all the atomic vectors in the facility node and turn them into a single row table; we then stitch the columns of this table together with the table of employee information using list_cbind. We could discuss the remainder of the transformations needed, but the awesome thing is that the remainder of the transformations just rinse and repeat the transformations we’ve described for the remaining levels of the list. This also means that the above code can handle arbitrary levels of hierarchy in the list2. Compare this to how we would handle this using, say, {tidyr}.

library(tidyr)
library(dplyr)

company_df &lt;- tibble(
  data = list(company)
) |&gt;
  unnest_wider(data) |&gt;
  rename(
    company_id = id,
    company = name
  ) |&gt;
  unnest_longer(regions) |&gt;
  unnest_wider(regions) |&gt;
  rename(
    region_id = id,
    region = name
  ) |&gt;
  unnest_longer(facilities) |&gt;
  unnest_wider(facilities) |&gt;
  rename(
    facility_id = id,
    facility = name
  ) |&gt;
  unnest_longer(employees) |&gt;
  unnest_wider(employees) |&gt;
  rename(
    employee_id = id,
    employee = name
  )

#  Result (ID columns omitted for brevity):
#  A tibble: 10 × 4
#    company     region   facility        employee  
#    &lt;chr&gt;       &lt;chr&gt;    &lt;chr&gt;           &lt;chr&gt;
#  1 Big Company Region A Facility Red    Satrina   
#  2 Big Company Region A Facility Red    Margeree  
#  3 Big Company Region A Facility Blue   Aariona   
#  4 Big Company Region A Facility Blue   Letrina   
#  5 Big Company Region A Facility Blue   Ehron     
#  6 Big Company Region A Facility Green  Uyless    
#  7 Big Company Region B Facility Yellow Uche      
#  8 Big Company Region B Facility Yellow Lilliam   
#  9 Big Company Region B Facility Yellow Vaidehi   
# 10 Big Company Region B Facility Yellow Shieka      

While the code above achieves the same result, it lacks some of the elegance we get using modify_tree because we have to add successive calls to unnest_longer and unnest_wider for each additional layer of hierarchy.

The Polling Pattern
The polling pattern, or the async request-reply pattern, is one solution REST developers have come up with to handle long running tasks. With the polling pattern, you take your endpoint and turn it into four: one to accept the job, one to check status, one to retrieve results, and one to cancel. Here’s how they work together.

library(plumber2)
library(mirai)
library(promises)

daemons(4L, dispatcher = TRUE)

tasks &lt;- new.env()

# model_cache, model_train(), model_load(), model_load_memoised(), and 
# model_predict() remain unchanged from the previous example. See repo
# for the complete code.

#* Train ML model.
#* @post /train
function(response) {
  id &lt;- uuid::UUIDgenerate(n = 1)
  location &lt;- paste0("/train/", id, "/status")
  task &lt;- list(
    id = id,
    created = Sys.time(),
    status = "queued",
    task = NULL,
    error = NULL
  )
  tasks[[id]] &lt;- task
  tasks[[id]][["task"]] &lt;- mirai(
    {
      result &lt;- model_train(palmerpenguins::penguins)
      result
    },
    model_train = model_train
  )
  tasks[[id]][["status"]] &lt;- "running"
  response$status &lt;- 202L
  response$set_header("Location", location)
  response$set_header("Retry-After", 5)
  response$body &lt;- list(
    message = "Task submitted."
  )
  response$Next
}

#* Query status of model training run.
#* @get /train/&lt;id&gt;/status
function(id, response) {
  task_exists_ind &lt;- id %in% names(tasks)
  if (!task_exists_ind) {
    response$status &lt;- 404L
    response$body &lt;- list(message = paste0("Task ID ", id, " not found."))
    return(response$Next)
  }
  task &lt;- tasks[[id]]
  if (task$status == "running" & unresolved(task$task)) {
    # Logic for when the task is still running.
    return(response$Next)
  }
  if (
    task$status == "running" &
      !unresolved(task$task) &
      is_mirai_error(task$task$data)
  ) {
    # Logic for when the task fails.
    return(response$Next)
  }
  if (
    task$status == "running" &
      !unresolved(task$task) &
      !is_mirai_error(task$task$data)
  ) {
    task$status &lt;- "completed"
    task$result_url &lt;- paste0("/train/", id, "/result")
    tasks[[id]] &lt;- task
    memoise::forget(model_load_memoised)
    out &lt;- list(
      id = id,
      created = task$created,
      status = task$status,
      result_url = task$result_url
    )
    response$status &lt;- 200L
    response$body &lt;- out
    return(response$Next)
  }
  if (task$status == "cancelled") {
    # Logic for when the task is cancelled
    return(response$Next)
  }
}

#* Get the result of the training run
#* @get /train/&lt;id&gt;/result
function(id, response) {
  task_exists_ind &lt;- id %in% names(tasks)
  if (!task_exists_ind) {
    response$status &lt;- 404L
    response$body &lt;- jsonlite::toJSON(
      list(message = paste0("Task ID ", id, " not found."))
    )
    return(response$Next)
  }
  task &lt;- tasks[[id]]
  out &lt;- list(
    id = task$id,
    created = task$created,
    result = task$task$data
  )
  response$status &lt;- 200L
  response$body &lt;- out
  return(response$Next)
}

#* Cancel a training run.
#* @delete /train/&lt;id&gt;
function(id, response) {
  task_exists_ind &lt;- id %in% names(tasks)
  if (!task_exists_ind) {
    response$status &lt;- 404L
    response$body &lt;- jsonlite::toJSON(
      list(message = paste0("Task ID ", id, " not found."))
    )
    return(response$Next)
  }
  task &lt;- tasks[[id]]
  stop_mirai(task$task)
  task$status &lt;- "cancelled"
  tasks[[id]] &lt;- task
  out &lt;- list(
    id = task$id,
    created = task$created,
    status = task$status
  )
  response$status &lt;- 200L
  response$body &lt;- out
  return(response$Next)
}

